import type { MouseEventHandler, ReactNode } from 'react';
import type { TestComponentProps } from 'src/types/test-component';
/**
 * Размер триггера Collapse (наследуется от Link).
 */
export type CollapseSize = 'large' | 'medium' | 'small';
/**
 * Публичный тип пропсов компонента Collapse.
 *
 * @example
 * ```tsx
 * // С контентом
 * <Collapse expanded={open} onToggle={setOpen}>
 *   <p>Скрываемый контент</p>
 * </Collapse>
 *
 * // Без контента (таблицы, фильтры)
 * <Collapse expanded={showMore} onToggle={setShowMore} />
 * ```
 */
export interface CollapseProps extends TestComponentProps {
    /**
     * Развёрнут ли контент (controlled).
     */
    expanded?: boolean;
    /**
     * Начальное состояние (uncontrolled).
     * @default false
     */
    defaultExpanded?: boolean;
    /**
     * Вызывается при клике по триггеру. Передаётся новое значение expanded и событие.
     */
    onToggle?: (expanded: boolean, event: React.MouseEvent<HTMLElement>) => void;
    /**
     * Текст триггера при свёрнутом состоянии.
     * @default 'Развернуть'
     */
    labelCollapsed?: string;
    /**
     * Текст триггера при развёрнутом состоянии.
     * @default 'Свернуть'
     */
    labelExpanded?: string;
    /**
     * Размер триггера.
     * @default 'medium'
     */
    size?: CollapseSize;
    /**
     * Скрываемый контент. Опционально — без children только триггер (таблицы, фильтры).
     */
    children?: ReactNode;
    /**
     * Пользовательский класс корневого контейнера.
     */
    className?: string;
    /**
     * Пользовательский класс триггера (Link).
     */
    triggerClassName?: string;
    /**
     * Пользовательский класс контейнера контента.
     */
    contentClassName?: string;
    /**
     * Вызывается при раскрытии.
     */
    onExpand?: MouseEventHandler<HTMLElement>;
    /**
     * Вызывается при сворачивании.
     */
    onCollapse?: MouseEventHandler<HTMLElement>;
}
